
UPDATE annotation_tasks SET task_content = '{"prompt": "Implémente une fonction Python qui détecte les cycles dans un graphe orienté. Compare les approches DFS et BFS.", "response_a": "def has_cycle_dfs(graph):\n    visited = set()\n    rec_stack = set()\n    def dfs(node):\n        visited.add(node)\n        rec_stack.add(node)\n        for neighbor in graph.get(node, []):\n            if neighbor not in visited:\n                if dfs(neighbor): return True\n            elif neighbor in rec_stack:\n                return True\n        rec_stack.discard(node)\n        return False\n    return any(dfs(n) for n in graph if n not in visited)", "response_b": "def has_cycle(graph):\n    from collections import deque\n    in_degree = {n: 0 for n in graph}\n    for n in graph:\n        for nb in graph[n]:\n            in_degree[nb] = in_degree.get(nb, 0) + 1\n    queue = deque([n for n, d in in_degree.items() if d == 0])\n    count = 0\n    while queue:\n        node = queue.popleft()\n        count += 1\n        for nb in graph.get(node, []):\n            in_degree[nb] -= 1\n            if in_degree[nb] == 0: queue.append(nb)\n    return count != len(graph)"}'::jsonb WHERE id = '4bf34e91-d7be-4fe8-ba53-0ea169281335';

UPDATE annotation_tasks SET task_content = '{"prompt": "Écris une classe TypeScript pour un cache LRU (Least Recently Used) avec une capacité maximale configurable.", "response_a": "class LRUCache<K, V> {\n    private cache = new Map<K, V>();\n    constructor(private capacity: number) {}\n    get(key: K): V | undefined {\n        if (!this.cache.has(key)) return undefined;\n        const val = this.cache.get(key)!;\n        this.cache.delete(key);\n        this.cache.set(key, val);\n        return val;\n    }\n    put(key: K, value: V): void {\n        this.cache.delete(key);\n        if (this.cache.size >= this.capacity) {\n            this.cache.delete(this.cache.keys().next().value);\n        }\n        this.cache.set(key, value);\n    }\n}", "response_b": "class LRUCache {\n    cache: Record<string, any> = {};\n    order: string[] = [];\n    maxSize: number;\n    constructor(max: number) { this.maxSize = max; }\n    get(key: string) {\n        if (!(key in this.cache)) return null;\n        this.order = this.order.filter(k => k !== key);\n        this.order.push(key);\n        return this.cache[key];\n    }\n    set(key: string, val: any) {\n        if (this.order.length >= this.maxSize) {\n            const old = this.order.shift()!;\n            delete this.cache[old];\n        }\n        this.cache[key] = val;\n        this.order.push(key);\n    }\n}"}'::jsonb WHERE id = '38fb3b7e-d6f6-4ebf-b26b-e16fd331623b';

UPDATE annotation_tasks SET task_content = '{"prompt": "Compare deux implémentations de rate limiter en Go : token bucket vs sliding window.", "response_a": "type TokenBucket struct {\n    rate     float64\n    capacity float64\n    tokens   float64\n    lastTime time.Time\n    mu       sync.Mutex\n}\nfunc (tb *TokenBucket) Allow() bool {\n    tb.mu.Lock()\n    defer tb.mu.Unlock()\n    now := time.Now()\n    elapsed := now.Sub(tb.lastTime).Seconds()\n    tb.tokens = math.Min(tb.capacity, tb.tokens+elapsed*tb.rate)\n    tb.lastTime = now\n    if tb.tokens >= 1 {\n        tb.tokens--\n        return true\n    }\n    return false\n}", "response_b": "type SlidingWindow struct {\n    windowSize time.Duration\n    maxReqs    int\n    requests   []time.Time\n    mu         sync.Mutex\n}\nfunc (sw *SlidingWindow) Allow() bool {\n    sw.mu.Lock()\n    defer sw.mu.Unlock()\n    now := time.Now()\n    cutoff := now.Add(-sw.windowSize)\n    filtered := make([]time.Time, 0)\n    for _, t := range sw.requests {\n        if t.After(cutoff) { filtered = append(filtered, t) }\n    }\n    sw.requests = filtered\n    if len(sw.requests) >= sw.maxReqs { return false }\n    sw.requests = append(sw.requests, now)\n    return true\n}"}'::jsonb WHERE id = '527c053c-d52b-4625-bd0e-4219176ed3c5';

UPDATE annotation_tasks SET task_content = '{"prompt": "Propose une solution pour valider un formulaire complexe en React avec des dépendances entre champs.", "response_a": "import { useForm } from \"react-hook-form\";\nimport { z } from \"zod\";\nimport { zodResolver } from \"@hookform/resolvers/zod\";\n\nconst schema = z.object({\n    startDate: z.date(),\n    endDate: z.date(),\n    budget: z.number().positive(),\n}).refine(d => d.endDate > d.startDate, {\n    message: \"La date de fin doit être après la date de début\",\n    path: [\"endDate\"],\n});\n\nexport function MyForm() {\n    const { register, handleSubmit, formState: { errors } } = useForm({\n        resolver: zodResolver(schema)\n    });\n    return <form onSubmit={handleSubmit(onSubmit)}>...</form>;\n}", "response_b": "function MyForm() {\n    const [values, setValues] = useState({});\n    const [errors, setErrors] = useState({});\n    const validate = () => {\n        const errs = {};\n        if (!values.startDate) errs.startDate = \"Requis\";\n        if (!values.endDate) errs.endDate = \"Requis\";\n        if (values.endDate <= values.startDate) errs.endDate = \"Doit être après début\";\n        if (values.budget <= 0) errs.budget = \"Doit être positif\";\n        setErrors(errs);\n        return Object.keys(errs).length === 0;\n    };\n    const handleSubmit = () => { if (validate()) submitForm(values); };\n    return <div>...</div>;\n}"}'::jsonb WHERE id = '13adfa5a-8b28-467f-8afa-4de99676d708';

UPDATE annotation_tasks SET task_content = '{"prompt": "Implémente un middleware Express.js pour gérer l''authentification JWT avec refresh tokens.", "response_a": "const jwt = require(\"jsonwebtoken\");\nconst authMiddleware = (req, res, next) => {\n    const token = req.headers.authorization?.split(\" \")[1];\n    if (!token) return res.status(401).json({ error: \"Token manquant\" });\n    try {\n        const decoded = jwt.verify(token, process.env.JWT_SECRET);\n        req.user = decoded;\n        next();\n    } catch (err) {\n        if (err.name === \"TokenExpiredError\") {\n            return res.status(401).json({ error: \"Token expiré\", code: \"TOKEN_EXPIRED\" });\n        }\n        return res.status(403).json({ error: \"Token invalide\" });\n    }\n};", "response_b": "function authMiddleware(req, res, next) {\n    const token = req.cookies.token || req.headers[\"x-auth\"];\n    if (!token) return res.redirect(\"/login\");\n    const decoded = jwt.decode(token);\n    if (!decoded) return res.status(400).send(\"Bad token\");\n    if (decoded.exp < Date.now() / 1000) {\n        const refresh = req.cookies.refresh;\n        if (refresh) {\n            const newToken = jwt.sign({ id: decoded.id }, SECRET, { expiresIn: \"1h\" });\n            res.cookie(\"token\", newToken);\n            req.user = decoded;\n            return next();\n        }\n        return res.redirect(\"/login\");\n    }\n    req.user = decoded;\n    next();\n}"}'::jsonb WHERE id = '45f2c5d2-c82a-4c7d-abea-5b487c3b0479';

UPDATE annotation_tasks SET task_content = '{"prompt": "Conçois un système de pagination cursor-based pour une API REST avec PostgreSQL.", "response_a": "async function getItems(cursor, limit = 20) {\n    const query = `\n        SELECT id, title, created_at\n        FROM items\n        WHERE ($1::timestamptz IS NULL OR created_at < $1)\n        ORDER BY created_at DESC\n        LIMIT $2\n    `;\n    const { rows } = await pool.query(query, [cursor, limit + 1]);\n    const hasMore = rows.length > limit;\n    const items = rows.slice(0, limit);\n    const nextCursor = hasMore ? items[items.length - 1].created_at : null;\n    return { items, nextCursor, hasMore };\n}", "response_b": "app.get(\"/items\", async (req, res) => {\n    const page = parseInt(req.query.page) || 1;\n    const limit = 20;\n    const offset = (page - 1) * limit;\n    const items = await db.query(\"SELECT * FROM items ORDER BY id LIMIT $1 OFFSET $2\", [limit, offset]);\n    const total = await db.query(\"SELECT COUNT(*) FROM items\");\n    res.json({ items: items.rows, total: total.rows[0].count, page, totalPages: Math.ceil(total.rows[0].count / limit) });\n});"}'::jsonb WHERE id = 'e1578eae-c916-4146-8bc2-2daac46d998a';

UPDATE annotation_tasks SET task_content = '{"prompt": "Écris un hook React personnalisé useDebounce avec cancel et flush.", "response_a": "function useDebounce<T>(value: T, delay: number) {\n    const [debouncedValue, setDebouncedValue] = useState(value);\n    const timerRef = useRef<NodeJS.Timeout>();\n    useEffect(() => {\n        timerRef.current = setTimeout(() => setDebouncedValue(value), delay);\n        return () => clearTimeout(timerRef.current);\n    }, [value, delay]);\n    const cancel = useCallback(() => clearTimeout(timerRef.current), []);\n    const flush = useCallback(() => {\n        clearTimeout(timerRef.current);\n        setDebouncedValue(value);\n    }, [value]);\n    return { debouncedValue, cancel, flush };\n}", "response_b": "function useDebounce(value, delay) {\n    const [debounced, setDebounced] = useState(value);\n    useEffect(() => {\n        const handler = setTimeout(() => setDebounced(value), delay);\n        return () => clearTimeout(handler);\n    }, [value, delay]);\n    return debounced;\n}"}'::jsonb WHERE id = '45665710-4abf-4222-aedc-4bf2701529ba';

UPDATE annotation_tasks SET task_content = '{"prompt": "Implémente un worker pool en Python avec asyncio pour traiter des requêtes HTTP concurrentes.", "response_a": "import asyncio\nimport aiohttp\n\nasync def worker(name, queue, session, results):\n    while True:\n        url = await queue.get()\n        try:\n            async with session.get(url) as resp:\n                data = await resp.json()\n                results.append({\"url\": url, \"status\": resp.status, \"data\": data})\n        except Exception as e:\n            results.append({\"url\": url, \"error\": str(e)})\n        finally:\n            queue.task_done()\n\nasync def process_urls(urls, max_workers=10):\n    queue = asyncio.Queue()\n    results = []\n    for url in urls: queue.put_nowait(url)\n    async with aiohttp.ClientSession() as session:\n        workers = [asyncio.create_task(worker(f\"w-{i}\", queue, session, results)) for i in range(max_workers)]\n        await queue.join()\n        for w in workers: w.cancel()\n    return results", "response_b": "import requests\nfrom concurrent.futures import ThreadPoolExecutor\n\ndef fetch(url):\n    try:\n        r = requests.get(url, timeout=10)\n        return {\"url\": url, \"status\": r.status_code}\n    except:\n        return {\"url\": url, \"error\": \"failed\"}\n\ndef process_urls(urls):\n    with ThreadPoolExecutor(max_workers=5) as pool:\n        return list(pool.map(fetch, urls))"}'::jsonb WHERE id = 'd3cb42eb-31c3-4bfb-96b6-98d5c90f9eda';

UPDATE annotation_tasks SET task_content = '{"prompt": "Compare deux approches pour gérer l''état global dans une app React : Context + useReducer vs Zustand.", "response_a": "// Zustand\nimport { create } from \"zustand\";\nimport { devtools, persist } from \"zustand/middleware\";\n\ninterface AppState {\n    user: User | null;\n    theme: \"light\" | \"dark\";\n    notifications: Notification[];\n    setUser: (user: User | null) => void;\n    toggleTheme: () => void;\n    addNotification: (n: Notification) => void;\n    clearNotifications: () => void;\n}\n\nexport const useAppStore = create<AppState>()(devtools(persist((set) => ({\n    user: null, theme: \"light\", notifications: [],\n    setUser: (user) => set({ user }),\n    toggleTheme: () => set((s) => ({ theme: s.theme === \"light\" ? \"dark\" : \"light\" })),\n    addNotification: (n) => set((s) => ({ notifications: [...s.notifications, n] })),\n    clearNotifications: () => set({ notifications: [] }),\n}), { name: \"app-store\" })));", "response_b": "// Context + useReducer\nconst AppContext = createContext();\nfunction appReducer(state, action) {\n    switch (action.type) {\n        case \"SET_USER\": return { ...state, user: action.payload };\n        case \"TOGGLE_THEME\": return { ...state, theme: state.theme === \"light\" ? \"dark\" : \"light\" };\n        case \"ADD_NOTIFICATION\": return { ...state, notifications: [...state.notifications, action.payload] };\n        default: return state;\n    }\n}\nfunction AppProvider({ children }) {\n    const [state, dispatch] = useReducer(appReducer, { user: null, theme: \"light\", notifications: [] });\n    return <AppContext.Provider value={{ state, dispatch }}>{children}</AppContext.Provider>;\n}"}'::jsonb WHERE id = '47c75488-c156-4c2f-885e-900aa2bad4ad';

UPDATE annotation_tasks SET task_content = '{"prompt": "Implémente un système de retry avec exponential backoff et jitter en TypeScript.", "response_a": "async function retry<T>(\n    fn: () => Promise<T>,\n    options: { maxRetries?: number; baseDelay?: number; maxDelay?: number } = {}\n): Promise<T> {\n    const { maxRetries = 3, baseDelay = 1000, maxDelay = 30000 } = options;\n    for (let attempt = 0; attempt <= maxRetries; attempt++) {\n        try {\n            return await fn();\n        } catch (error) {\n            if (attempt === maxRetries) throw error;\n            const expDelay = Math.min(baseDelay * Math.pow(2, attempt), maxDelay);\n            const jitter = expDelay * (0.5 + Math.random() * 0.5);\n            await new Promise(r => setTimeout(r, jitter));\n        }\n    }\n    throw new Error(\"Unreachable\");\n}", "response_b": "async function retry(fn, retries = 3) {\n    for (let i = 0; i < retries; i++) {\n        try { return await fn(); }\n        catch (e) {\n            if (i === retries - 1) throw e;\n            await new Promise(r => setTimeout(r, 1000 * (i + 1)));\n        }\n    }\n}"}'::jsonb WHERE id = 'b717db43-8c60-478a-83ea-49fcee68f6b9';

UPDATE annotation_tasks SET task_content = '{"prompt": "Crée un composant Vue.js pour un éditeur de markdown temps réel avec preview côte à côte.", "response_a": "<!-- MarkdownEditor.vue -->\n<template>\n  <div class=\"flex h-full\">\n    <textarea v-model=\"source\" class=\"w-1/2 p-4 font-mono resize-none border-r\" @input=\"debouncedRender\" />\n    <div class=\"w-1/2 p-4 prose overflow-auto\" v-html=\"rendered\" />\n  </div>\n</template>\n<script setup>\nimport { ref, watch } from \"vue\";\nimport { marked } from \"marked\";\nimport DOMPurify from \"dompurify\";\nimport { useDebounceFn } from \"@vueuse/core\";\nconst source = ref(\"\");\nconst rendered = ref(\"\");\nconst debouncedRender = useDebounceFn(() => {\n    rendered.value = DOMPurify.sanitize(marked.parse(source.value));\n}, 150);\nwatch(source, debouncedRender, { immediate: true });\n</script>", "response_b": "<template>\n  <div>\n    <textarea v-model=\"text\" style=\"width:50%;float:left\" />\n    <div style=\"width:50%;float:left\" v-html=\"preview\" />\n  </div>\n</template>\n<script>\nimport marked from \"marked\";\nexport default {\n    data() { return { text: \"\" } },\n    computed: { preview() { return marked(this.text); } }\n}\n</script>"}'::jsonb WHERE id = '225f972d-9467-4620-85a5-44092bbd587f';

UPDATE annotation_tasks SET task_content = '{"prompt": "Écris un script Bash robuste pour sauvegarder une base PostgreSQL avec rotation et notification Slack.", "response_a": "#!/bin/bash\nset -euo pipefail\n\nDB_NAME=\"${1:?Usage: $0 <db_name>}\"\nBACKUP_DIR=\"/var/backups/postgres\"\nRETENTION_DAYS=30\nSLACK_WEBHOOK=\"${SLACK_WEBHOOK_URL}\"\nTIMESTAMP=$(date +%Y%m%d_%H%M%S)\nFILE=\"${BACKUP_DIR}/${DB_NAME}_${TIMESTAMP}.sql.gz\"\n\nmkdir -p \"$BACKUP_DIR\"\npg_dump \"$DB_NAME\" | gzip > \"$FILE\"\nSIZE=$(du -h \"$FILE\" | cut -f1)\n\nfind \"$BACKUP_DIR\" -name \"${DB_NAME}_*.sql.gz\" -mtime +$RETENTION_DAYS -delete\nCOUNT=$(find \"$BACKUP_DIR\" -name \"${DB_NAME}_*.sql.gz\" | wc -l)\n\ncurl -s -X POST \"$SLACK_WEBHOOK\" -H \"Content-Type: application/json\" -d \"{\\\"text\\\": \\\"✅ Backup ${DB_NAME}: ${SIZE} (${COUNT} archives)\\\"}\"\necho \"Backup terminé: $FILE ($SIZE)\"", "response_b": "#!/bin/bash\npg_dump mydb > /tmp/backup.sql\necho \"done\""}'::jsonb WHERE id = '94582320-c9c5-4bfd-8d60-0a4b7c2a0f4f';

UPDATE annotation_tasks SET task_content = '{"prompt": "Implémente un observable pattern en Rust avec des subscribers typés.", "response_a": "use std::collections::HashMap;\nuse std::sync::{Arc, Mutex};\n\ntype Callback<T> = Box<dyn Fn(&T) + Send + Sync>;\n\nstruct Observable<T> {\n    listeners: Arc<Mutex<HashMap<u64, Callback<T>>>>,\n    next_id: u64,\n}\n\nimpl<T> Observable<T> {\n    fn new() -> Self {\n        Observable { listeners: Arc::new(Mutex::new(HashMap::new())), next_id: 0 }\n    }\n    fn subscribe(&mut self, callback: impl Fn(&T) + Send + Sync + ''static) -> u64 {\n        let id = self.next_id;\n        self.next_id += 1;\n        self.listeners.lock().unwrap().insert(id, Box::new(callback));\n        id\n    }\n    fn unsubscribe(&self, id: u64) {\n        self.listeners.lock().unwrap().remove(&id);\n    }\n    fn notify(&self, event: &T) {\n        for cb in self.listeners.lock().unwrap().values() { cb(event); }\n    }\n}", "response_b": "struct EventEmitter {\n    callbacks: Vec<fn(String)>,\n}\nimpl EventEmitter {\n    fn on(&mut self, cb: fn(String)) { self.callbacks.push(cb); }\n    fn emit(&self, data: String) { for cb in &self.callbacks { cb(data.clone()); } }\n}"}'::jsonb WHERE id = '0d4d011f-ed62-4b5e-bd76-532bfc36e282';

UPDATE annotation_tasks SET task_content = '{"prompt": "Conçois un middleware de logging structuré pour une API Fastify avec corrélation de requêtes.", "response_a": "import Fastify from \"fastify\";\nimport { randomUUID } from \"crypto\";\nimport pino from \"pino\";\n\nconst app = Fastify({\n    logger: pino({ level: \"info\", formatters: { level: (label) => ({ level: label }) } }),\n    genReqId: () => randomUUID(),\n});\n\napp.addHook(\"onRequest\", (req, reply, done) => {\n    req.log.info({ method: req.method, url: req.url, correlationId: req.id, userAgent: req.headers[\"user-agent\"] }, \"request_start\");\n    (req as any).startTime = Date.now();\n    done();\n});\n\napp.addHook(\"onResponse\", (req, reply, done) => {\n    const duration = Date.now() - (req as any).startTime;\n    req.log.info({ method: req.method, url: req.url, statusCode: reply.statusCode, duration, correlationId: req.id }, \"request_end\");\n    done();\n});", "response_b": "app.use((req, res, next) => {\n    console.log(`${new Date().toISOString()} ${req.method} ${req.url}`);\n    const start = Date.now();\n    res.on(\"finish\", () => {\n        console.log(`${req.method} ${req.url} ${res.statusCode} ${Date.now() - start}ms`);\n    });\n    next();\n});"}'::jsonb WHERE id = '7cc9f140-0544-4c5e-a24c-b917f05764af';

UPDATE annotation_tasks SET task_content = '{"prompt": "Crée un système de feature flags côté serveur avec rollout progressif et ciblage utilisateur.", "response_a": "interface FeatureFlag {\n    name: string;\n    enabled: boolean;\n    rolloutPercentage: number;\n    targetRules: Array<{ field: string; operator: \"eq\" | \"in\" | \"gt\"; value: any }>;\n}\n\nclass FeatureFlagService {\n    private flags: Map<string, FeatureFlag> = new Map();\n    \n    isEnabled(flagName: string, context: { userId: string; country?: string; plan?: string }): boolean {\n        const flag = this.flags.get(flagName);\n        if (!flag || !flag.enabled) return false;\n        \n        // Check targeting rules\n        for (const rule of flag.targetRules) {\n            const value = context[rule.field];\n            if (rule.operator === \"eq\" && value !== rule.value) return false;\n            if (rule.operator === \"in\" && !rule.value.includes(value)) return false;\n        }\n        \n        // Deterministic rollout based on userId hash\n        const hash = this.hashCode(context.userId + flagName);\n        return (hash % 100) < flag.rolloutPercentage;\n    }\n    \n    private hashCode(str: string): number {\n        let hash = 0;\n        for (let i = 0; i < str.length; i++) {\n            hash = ((hash << 5) - hash) + str.charCodeAt(i);\n            hash |= 0;\n        }\n        return Math.abs(hash);\n    }\n}", "response_b": "const features = {\n    newDashboard: process.env.FEATURE_NEW_DASHBOARD === \"true\",\n    darkMode: true,\n};\nfunction isEnabled(name) { return features[name] || false; }"}'::jsonb WHERE id = 'defe5e0d-df1a-4058-b7a0-157e956f46a4';

UPDATE annotation_tasks SET task_content = '{"prompt": "Implémente un système de file d''attente de messages avec dead letter queue en Node.js.", "response_a": "class MessageQueue {\n    private queue: Array<{ id: string; payload: any; attempts: number; maxRetries: number }> = [];\n    private deadLetterQueue: Array<{ message: any; error: string; failedAt: Date }> = [];\n    private processing = false;\n\n    async enqueue(payload: any, maxRetries = 3) {\n        this.queue.push({ id: crypto.randomUUID(), payload, attempts: 0, maxRetries });\n        if (!this.processing) this.processNext();\n    }\n\n    private async processNext() {\n        this.processing = true;\n        while (this.queue.length > 0) {\n            const msg = this.queue.shift()!;\n            try {\n                await this.handler(msg.payload);\n            } catch (err) {\n                msg.attempts++;\n                if (msg.attempts >= msg.maxRetries) {\n                    this.deadLetterQueue.push({ message: msg, error: String(err), failedAt: new Date() });\n                } else {\n                    const delay = Math.pow(2, msg.attempts) * 1000;\n                    setTimeout(() => this.queue.push(msg), delay);\n                }\n            }\n        }\n        this.processing = false;\n    }\n}", "response_b": "const queue = [];\nfunction addToQueue(msg) { queue.push(msg); }\nfunction processQueue(handler) {\n    while (queue.length) {\n        const msg = queue.shift();\n        try { handler(msg); } catch { console.error(\"failed\", msg); }\n    }\n}"}'::jsonb WHERE id = '8f49e81b-2c36-4eb0-ad15-e3639b3a8920';

UPDATE annotation_tasks SET task_content = '{"prompt": "Écris un algorithme de diff textuel simplifié (type git diff) en Python.", "response_a": "def lcs_diff(old_lines, new_lines):\n    m, n = len(old_lines), len(new_lines)\n    dp = [[0] * (n + 1) for _ in range(m + 1)]\n    for i in range(1, m + 1):\n        for j in range(1, n + 1):\n            if old_lines[i-1] == new_lines[j-1]:\n                dp[i][j] = dp[i-1][j-1] + 1\n            else:\n                dp[i][j] = max(dp[i-1][j], dp[i][j-1])\n    \n    result = []\n    i, j = m, n\n    while i > 0 or j > 0:\n        if i > 0 and j > 0 and old_lines[i-1] == new_lines[j-1]:\n            result.append((\" \", old_lines[i-1]))\n            i -= 1; j -= 1\n        elif j > 0 and (i == 0 or dp[i][j-1] >= dp[i-1][j]):\n            result.append((\"+\", new_lines[j-1]))\n            j -= 1\n        else:\n            result.append((\"-\", old_lines[i-1]))\n            i -= 1\n    return list(reversed(result))", "response_b": "def diff(old, new):\n    result = []\n    for line in old:\n        if line not in new: result.append(f\"- {line}\")\n    for line in new:\n        if line not in old: result.append(f\"+ {line}\")\n    return result"}'::jsonb WHERE id = 'f9b273c1-813f-4f9e-a98f-3407cc0edf46';

UPDATE annotation_tasks SET task_content = '{"prompt": "Implémente un connection pool pour PostgreSQL en Java avec health check et auto-reconnection.", "response_a": "public class PgConnectionPool {\n    private final BlockingQueue<Connection> pool;\n    private final String url;\n    private final int maxSize;\n    private final ScheduledExecutorService healthChecker;\n\n    public PgConnectionPool(String url, int maxSize) {\n        this.url = url;\n        this.maxSize = maxSize;\n        this.pool = new LinkedBlockingQueue<>(maxSize);\n        for (int i = 0; i < maxSize; i++) pool.offer(createConnection());\n        this.healthChecker = Executors.newSingleThreadScheduledExecutor();\n        healthChecker.scheduleAtFixedRate(this::checkHealth, 30, 30, TimeUnit.SECONDS);\n    }\n\n    public Connection acquire(long timeoutMs) throws Exception {\n        Connection conn = pool.poll(timeoutMs, TimeUnit.MILLISECONDS);\n        if (conn == null) throw new TimeoutException(\"Pool exhausted\");\n        if (!conn.isValid(2)) { conn.close(); conn = createConnection(); }\n        return conn;\n    }\n\n    public void release(Connection conn) {\n        if (!pool.offer(conn)) { try { conn.close(); } catch (Exception e) {} }\n    }\n\n    private void checkHealth() {\n        List<Connection> toCheck = new ArrayList<>();\n        pool.drainTo(toCheck);\n        for (Connection c : toCheck) {\n            try { if (c.isValid(1)) pool.offer(c); else { c.close(); pool.offer(createConnection()); } }\n            catch (Exception e) { pool.offer(createConnection()); }\n        }\n    }\n}", "response_b": "class SimplePool {\n    List<Connection> connections = new ArrayList<>();\n    Connection get() {\n        if (connections.isEmpty()) return DriverManager.getConnection(url);\n        return connections.remove(0);\n    }\n    void release(Connection c) { connections.add(c); }\n}"}'::jsonb WHERE id = '17ce401f-014a-4b7b-bea5-2063e24399bf';

UPDATE annotation_tasks SET task_content = '{"prompt": "Crée un système de permissions RBAC (Role-Based Access Control) flexible en TypeScript.", "response_a": "type Permission = string;\ntype Role = { name: string; permissions: Permission[]; inherits?: string[] };\n\nclass RBAC {\n    private roles = new Map<string, Role>();\n\n    addRole(role: Role) { this.roles.set(role.name, role); }\n\n    private getPermissions(roleName: string, visited = new Set<string>()): Set<Permission> {\n        if (visited.has(roleName)) return new Set();\n        visited.add(roleName);\n        const role = this.roles.get(roleName);\n        if (!role) return new Set();\n        const perms = new Set(role.permissions);\n        for (const parent of role.inherits || []) {\n            for (const p of this.getPermissions(parent, visited)) perms.add(p);\n        }\n        return perms;\n    }\n\n    can(roleName: string, permission: Permission): boolean {\n        return this.getPermissions(roleName).has(permission);\n    }\n\n    middleware(permission: Permission) {\n        return (req: any, res: any, next: any) => {\n            if (!this.can(req.user?.role, permission)) return res.status(403).json({ error: \"Forbidden\" });\n            next();\n        };\n    }\n}", "response_b": "function checkPermission(user, action) {\n    const permissions = { admin: [\"read\", \"write\", \"delete\"], user: [\"read\"] };\n    return permissions[user.role]?.includes(action) || false;\n}"}'::jsonb WHERE id = 'e409cd37-840e-40f2-967f-2ffec37ba4fb';

UPDATE annotation_tasks SET task_content = '{"prompt": "Implémente un moteur de templates simple (type Mustache) en JavaScript.", "response_a": "function render(template, data) {\n    // Handle sections {{#key}}...{{/key}}\n    let result = template.replace(/\\{\\{#(\\w+)\\}\\}([\\s\\S]*?)\\{\\{\\/(\\1)\\}\\}/g, (_, key, content) => {\n        const value = resolve(data, key);\n        if (Array.isArray(value)) return value.map(item => render(content, { ...data, ...item })).join(\"\");\n        if (value) return render(content, data);\n        return \"\";\n    });\n    // Handle inverted sections {{^key}}...{{/key}}\n    result = result.replace(/\\{\\{\\^(\\w+)\\}\\}([\\s\\S]*?)\\{\\{\\/(\\1)\\}\\}/g, (_, key, content) => {\n        const value = resolve(data, key);\n        return !value || (Array.isArray(value) && value.length === 0) ? render(content, data) : \"\";\n    });\n    // Handle variables {{key}} with HTML escaping\n    result = result.replace(/\\{\\{(\\w+(?:\\.\\w+)*)\\}\\}/g, (_, key) => escapeHtml(String(resolve(data, key) ?? \"\")));\n    // Handle unescaped {{{key}}}\n    result = result.replace(/\\{\\{\\{(\\w+(?:\\.\\w+)*)\\}\\}\\}/g, (_, key) => String(resolve(data, key) ?? \"\"));\n    return result;\n}\nfunction resolve(obj, path) {\n    return path.split(\".\").reduce((o, k) => o?.[k], obj);\n}\nfunction escapeHtml(s) {\n    return s.replace(/&/g,\"&amp;\").replace(/</g,\"&lt;\").replace(/>/g,\"&gt;\").replace(/\"/g,\"&quot;\");\n}", "response_b": "function template(str, data) {\n    return str.replace(/\\{\\{(\\w+)\\}\\}/g, (_, key) => data[key] || \"\");\n}"}'::jsonb WHERE id = '5fa5483b-499d-4e12-a87d-a1b98b57ded7';
